class Solution:
    def minimizeConcatenatedLength(self, words: List[str]) -> int:
        n = len(words)
        # dp[i][s][e] = min length of string after processing first i words, ending with 'e' and starting with 's'
        dp = {}
        # Initialize with the first word
        first_word = words[0]
        dp[(first_word[0], first_word[-1])] = len(first_word)

        for i in range(1, n):
            curr_dp = {}
            word = words[i]
            w_start, w_end = word[0], word[-1]
            w_len = len(word)

            for (prev_start, prev_end), prev_len in dp.items():
                # Option 1: join previous string with current word
                new_start = prev_start
                new_end = w_end
                new_len = prev_len + w_len
                if prev_end == w_start:
                    new_len -= 1
                key = (new_start, new_end)
                if key not in curr_dp or curr_dp[key] > new_len:
                    curr_dp[key] = new_len

                # Option 2: join current word with previous string
                new_start = w_start
                new_end = prev_end
                new_len = prev_len + w_len
                if w_end == prev_start:
                    new_len -= 1
                key = (new_start, new_end)
                if key not in curr_dp or curr_dp[key] > new_len:
                    curr_dp[key] = new_len

            dp = curr_dp

        # Find the minimum length among all possible states
        return min(dp.values())
